const functions = require('firebase-functions');
const admin = require('firebase-admin');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// Initialize Firebase Admin SDK
admin.initializeApp();

// Load environment variables securely
const SENDGRID_API_KEY = functions.config().sendgrid.key;
const TWILIO_ACCOUNT_SID = functions.config().twilio.sid;
const TWILIO_AUTH_TOKEN = functions.config().twilio.token;
const TWILIO_PHONE_NUMBER = functions.config().twilio.phone;

sgMail.setApiKey(SENDGRID_API_KEY);
const twilioClient = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

exports.sendNotification = functions.https.onRequest(async (req, res) => {
    const { email, phone, message } = req.body;

    // Validate input
    if (!email || !phone || !message) {
        return res.status(400).send('Invalid input');
    }

    try {
        // Send email
        const emailMsg = {
            to: email,
            from: 'your-email@example.com', // Use a verified SendGrid sender
            subject: 'Notification',
            text: message,
        };
        await sgMail.send(emailMsg);

        // Send SMS
        await twilioClient.messages.create({
            body: message,
            from: TWILIO_PHONE_NUMBER,
            to: phone,
        });

        return res.status(200).send('Notifications sent successfully');
    } catch (error) {
        console.error('Error sending notifications:', error);
        return res.status(500).send('Failed to send notifications');
    }
});